class Solution:
    def minOperations(self, n, m):
        # independent re-derivation: repeated Bellman-Ford-style relaxation over
        # the full explicit state graph (leading digit may also reach 0) instead
        # of a priority-queue search
        def is_prime(x):
            if x < 2:
                return False
            if x < 4:
                return True
            if x % 2 == 0:
                return False
            i = 3
            while i * i <= x:
                if x % i == 0:
                    return False
                i += 2
            return True
        if is_prime(n) or is_prime(m):
            return -1
        if n == m:
            return n
        d = len(str(n))
        nodes = [v for v in range(0, 10 ** d) if not is_prime(v)]
        dist = {v: float('inf') for v in nodes}
        dist[n] = n
        changed = True
        while changed:
            changed = False
            for v in nodes:
                if dist[v] == float('inf'):
                    continue
                digits = list(str(v).zfill(d))
                for i in range(d):
                    for delta in (1, -1):
                        nd = int(digits[i]) + delta
                        if 0 <= nd <= 9:
                            nxt_digits = digits[:]
                            nxt_digits[i] = str(nd)
                            nxt = int(''.join(nxt_digits))
                            if nxt in dist and dist[v] + nxt < dist[nxt]:
                                dist[nxt] = dist[v] + nxt
                                changed = True
        return dist[m] if dist[m] != float('inf') else -1

