import heapq
class Solution:
    def minOperations(self, n, m):
        def is_prime(x):
            if x < 2:
                return False
            if x < 4:
                return True
            if x % 2 == 0:
                return False
            i = 3
            while i * i <= x:
                if x % i == 0:
                    return False
                i += 2
            return True
        if is_prime(n) or is_prime(m):
            return -1
        if n == m:
            return n
        s_n = str(n)
        d = len(s_n)
        start = tuple(int(c) for c in s_n)
        target = tuple(int(c) for c in str(m).zfill(d))
        def val(t):
            v = 0
            for x in t:
                v = v * 10 + x
            return v
        dist = {start: val(start)}
        pq = [(val(start), start)]
        while pq:
            dv, u = heapq.heappop(pq)
            if dv > dist.get(u, float('inf')):
                continue
            if u == target:
                return dv
            for i in range(d):
                for delta in (1, -1):
                    nd_digit = u[i] + delta
                    if 0 <= nd_digit <= 9:
                        v = u[:i] + (nd_digit,) + u[i + 1:]
                        vv = val(v)
                        if is_prime(vv):
                            continue
                        nd = dv + vv
                        if nd < dist.get(v, float('inf')):
                            dist[v] = nd
                            heapq.heappush(pq, (nd, v))
        return -1

