var minOperations = function(n, m) {
    if (__isPrimeDOTMTIE(n) || __isPrimeDOTMTIE(m)) return -1;
    if (n === m) return n;
    const sN = String(n);
    const D = sN.length;
    const start = sN.split('').map(Number);
    const target = String(m).padStart(D, '0').split('').map(Number);
    function val(arr) {
        let v = 0;
        for (const d of arr) v = v * 10 + d;
        return v;
    }
    function key(arr) { return arr.join(''); }
    const targetKey = key(target);
    const dist = new Map();
    dist.set(key(start), val(start));
