    heap.push([val(start), start]);
    while (heap.size) {
        const [d, u] = heap.pop();
        const uKey = key(u);
        if (d > dist.get(uKey)) continue;
        if (uKey === targetKey) return d;
        for (let i = 0; i < D; i++) {
            for (const delta of [1, -1]) {
                const ndDigit = u[i] + delta;
                if (ndDigit >= 0 && ndDigit <= 9) {
